import os
from typing import List

import modal
import numpy as np

IMAGE = modal.Image.debian_slim().pip_install("numpy")
APP_NAME = "modal-gpu-batch-inference"
VOLUME_NAME = "modal-gpu-batch-inference-vol"
WEIGHTS_PATH = "/models/weights.npy"
SECRET_NAME = "modal-gpu-batch-inference-secret"

app = modal.App(APP_NAME)
volume = modal.Volume.from_name(VOLUME_NAME)

modal_gpu_batch_inference_output: dict = {}
globals()["modal-gpu-batch-inference-output"] = modal_gpu_batch_inference_output


@app.cls(
    gpu=modal.gpu.T4(),
    image=IMAGE,
    volumes={"/models": volume},
    secrets=[modal.Secret.from_name(SECRET_NAME)],
)
class GpuBatchInference:
    def __init__(self) -> None:
        self.weights: np.ndarray | None = None
        self.model_name: str | None = None

    @modal.enter()
    def load_or_initialize_weights(self) -> None:
        self.model_name = os.environ.get("MODEL_NAME", "gpu-batch-model")
        if os.path.exists(WEIGHTS_PATH):
            self.weights = np.load(WEIGHTS_PATH)
        else:
            self.weights = np.random.randn(128, 128).astype(np.float32)
            np.save(WEIGHTS_PATH, self.weights)
            volume.commit()

    @modal.method()
    def infer(self, batch: List[List[float]]) -> List[List[float]]:
        if self.weights is None:
            raise RuntimeError("Weights not initialized")
        batch_array = np.asarray(batch, dtype=np.float32)
        predictions = batch_array @ self.weights
        return predictions.tolist()


def _build_batches(batch_size: int) -> List[List[List[float]]]:
    total_samples = batch_size * 8
    data = np.random.randn(total_samples, 128).astype(np.float32)
    return [data[i : i + batch_size].tolist() for i in range(0, total_samples, batch_size)]


@app.local_entrypoint()
def main() -> None:
    batch_size = int(os.environ.get("INFERENCE_BATCH_SIZE", "16"))
    model = GpuBatchInference()
    batches = _build_batches(batch_size)
    predictions = list(model.infer.map(batches))

    flattened = np.asarray(predictions, dtype=np.float32).reshape(-1, 128)
    avg_prediction = float(flattened.mean())
    modal_gpu_batch_inference_output.update(
        {
            "model_name": os.environ.get("MODEL_NAME", "gpu-batch-model"),
            "total_samples": flattened.shape[0],
            "batches_processed": len(batches),
            "avg_prediction": avg_prediction,
            "weights_path": WEIGHTS_PATH,
        }
    )

    print("Aggregated output:")
    print(modal_gpu_batch_inference_output)
